import java.io.IOException;

public class CommandInjectionExample {

    public static void main(String[] args) {
        String userInput = "www.example.com";

        try {
            Process p = Runtime.getRuntime().exec("ping " + userInput);

            // The following code reads the output of the executed command
            // and prints it to the console
            java.util.Scanner s = new java.util.Scanner(p.getInputStream()).useDelimiter("\\A");
            System.out.println(s.hasNext() ? s.next() : "");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

