import java.io.IOException;

public class SecureCommandExecution {

    public static void main(String[] args) {
        String userInput = "www.example.com";

        // Validate user input to ensure it only contains allowed characters (e.g., alphanumeric, dot)
        if (!userInput.matches("[a-zA-Z0-9.]+")) {
            System.out.println("Invalid input");
            return;
        }

        try {
            // Use ProcessBuilder with a list of arguments to avoid command injection
            ProcessBuilder pb = new ProcessBuilder("ping", userInput);
            Process p = pb.start();

            // Read the output of the executed command and print it to the console
            java.util.Scanner s = new java.util.Scanner(p.getInputStream()).useDelimiter("\\A");
            System.out.println(s.hasNext() ? s.next() : "");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

